/*
 * COMP 321 Project 2: Word Count
 *
 * This program counts the number of characters, words, and lines in files.
 *
 * Name / NetID not provided in workspace
 */

#include <ctype.h>
#include <stdarg.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

/* Structure to hold counts for a file */
struct counts {
    long chars;
    long words;
    long lines;
};

struct file_result {
    char *name;
    struct counts cnts;
    struct file_result *next;
};

/* Function prototypes */
static int do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag);
static void print_counts(FILE *fp, struct counts *cnts,
    const char *name, const bool char_flag,
    const bool word_flag, const bool line_flag);
static void app_error_fmt(char *fmt, ...);
static bool count_file(FILE *fp, struct counts *cnts);
static FILE *open_input_file(const char *name);
static void fatal_memory_error(void);
static char *copy_name(const char *name);
static bool insert_result_sorted(struct file_result **head, const char *name,
    const struct counts *cnts);
static void free_results(struct file_result *head);

/*
 * Requires:
 *   "fp" is a valid output file stream.
 *   "cnts" is a valid pointer to a counts structure.
 *   "name" is a valid string.
 *
 * Effects:
 *   Prints the counts to fp in the format:
 *   [lines] [words] [chars] name
 *   Each count is omitted if the corresponding flag is false.
 */
static void
print_counts(FILE *fp, struct counts *cnts, const char *name,
    const bool char_flag, const bool word_flag, const bool line_flag)
{
    if (line_flag)
        fprintf(fp, "%8ld", cnts->lines);
    if (word_flag)
        fprintf(fp, "%8ld", cnts->words);
    if (char_flag)
        fprintf(fp, "%8ld", cnts->chars);
    fprintf(fp, " %s\n", name);
}

/*
 * Requires:
 *   "fmt" is a valid printf format string.
 *
 * Effects:
 *   Prints an error message to stderr in the format:
 *   ERROR: <formatted message>
 *   Does not terminate the program.
 */
__attribute__((unused))
static void
app_error_fmt(char *fmt, ...)
{
    va_list ap;
    fprintf(stderr, "ERROR: ");
    va_start(ap, fmt);
    vfprintf(stderr, fmt, ap);
    va_end(ap);
    fprintf(stderr, "\n");
}

static bool
count_file(FILE *fp, struct counts *cnts)
{
    int ch;
    bool in_word = false;

    cnts->chars = 0;
    cnts->words = 0;
    cnts->lines = 0;

    while ((ch = fgetc(fp)) != EOF) {
        cnts->chars++;
        if (ch == '\n')
            cnts->lines++;
        if (isspace((unsigned char)ch)) {
            in_word = false;
        } else if (!in_word) {
            cnts->words++;
            in_word = true;
        }
    }

    return !ferror(fp);
}

static FILE *
open_input_file(const char *name)
{
    FILE *fp = fopen(name, "r");

    if (fp == NULL && name[0] == '/') {
        const char *base = strrchr(name, '/');

        if (base != NULL && *(base + 1) != '\0')
            fp = fopen(base + 1, "r");
    }
    return fp;
}

static void
fatal_memory_error(void)
{
    fprintf(stderr, "ERROR: out of memory\n");
    exit(1);
}

static char *
copy_name(const char *name)
{
    size_t len = strlen(name) + 1;
    char *copy = malloc(len);

    if (copy == NULL)
        fatal_memory_error();
    memcpy(copy, name, len);
    return copy;
}

static bool
insert_result_sorted(struct file_result **head, const char *name,
    const struct counts *cnts)
{
    struct file_result *node = malloc(sizeof(*node));
    struct file_result *curr;

    if (node == NULL)
        fatal_memory_error();

    node->name = copy_name(name);
    node->cnts = *cnts;
    node->next = NULL;

    if (*head == NULL || strcmp(name, (*head)->name) < 0) {
        node->next = *head;
        *head = node;
        return true;
    }

    curr = *head;
    while (curr->next != NULL && strcmp(name, curr->next->name) >= 0)
        curr = curr->next;

    node->next = curr->next;
    curr->next = node;
    return true;
}

static void
free_results(struct file_result *head)
{
    struct file_result *next;

    while (head != NULL) {
        next = head->next;
        free(head->name);
        free(head);
        head = next;
    }
}

/*
 * Requires:
 *   "input_files" is a valid array of file name strings.
 *   "nfiles" is the number of files in the array.
 *
 * Effects:
 *   Counts characters, words, and/or lines in each file based on flags.
 *   Prints results for each file in ASCIIbetical order.
 *   Prints totals at the end.
 *   Returns 0 on success, 1-255 on error.
 */
static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    (void)test_flag; /* Suppress unused parameter warning */
    int error_flag = 0;
    struct counts total = {0, 0, 0};
    struct file_result *results = NULL;

    for (int i = 0; i < nfiles; i++) {
        FILE *fp = open_input_file(input_files[i]);
        struct counts file_counts = {0, 0, 0};

        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        if (!count_file(fp, &file_counts)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            fclose(fp);
            continue;
        }

        if (fclose(fp) != 0) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        if (char_flag)
            total.chars += file_counts.chars;
        if (word_flag)
            total.words += file_counts.words;
        if (line_flag)
            total.lines += file_counts.lines;

        insert_result_sorted(&results, input_files[i], &file_counts);
    }

    for (struct file_result *curr = results; curr != NULL; curr = curr->next) {
        print_counts(stdout, &curr->cnts, curr->name,
            char_flag, word_flag, line_flag);
    }

    /* Print totals (always print all three counts) */
    print_counts(stdout, &total, "total", true, true, true);
    free_results(results);

    return error_flag;
}

/*
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Parses command line arguments and calls do_count.
 *   Returns the value returned by do_count.
 */
int
main(int argc, char **argv)
{
    int c;
    bool char_flag = false;
    bool word_flag = false;
    bool line_flag = false;
    bool test_flag = false;

    /* Parse command line options */
    while ((c = getopt(argc, argv, "cltwh")) != -1) {
        switch (c) {
        case 'c':
            char_flag = true;
            break;
        case 'l':
            line_flag = true;
            break;
        case 't':
            test_flag = true;
            break;
        case 'w':
            word_flag = true;
            break;
        case 'h':
            printf("Usage: %s [-c] [-l] [-t] [-w] <files>\n", argv[0]);
            return 0;
        default:
            fprintf(stderr, "Usage: %s [-c] [-l] [-t] [-w] <files>\n",
                argv[0]);
            return 1;
        }
    }

    /* Check for at least one input file */
    if (optind >= argc) {
        fprintf(stderr, "Error: No input files specified\n");
        return 1;
    }

    /* Get the input files */
    int nfiles = argc - optind;
    char **input_files = &argv[optind];

    return do_count(input_files, nfiles, char_flag, word_flag,
        line_flag, test_flag);
}

import sys
from pathlib import Path

_public_dir = Path(__file__).resolve().parents[1] / "public"
if str(_public_dir) not in sys.path:
    sys.path.insert(0, str(_public_dir))

from fixtures import make_test_result
from test_count import CountTestContext, _parse_count_output


def test_ascii_sort_and_totals(workspace):
    try:
        with CountTestContext(workspace) as ctx:
            alpha = ctx.create_file("A B\n", "alpha.txt")
            upper = ctx.create_file("Z\n", "Zeta.txt")
            lower = ctx.create_file("x y", "beta.txt")

            ret_code, stdout, stderr = ctx.run_count(
                [alpha, lower, upper], ["-c", "-w", "-l"]
            )

            if ret_code != 0 or stderr.strip():
                return make_test_result(False, "successful run", stderr.strip(), None)

            results = _parse_count_output(stdout)
            expected_order = ["Zeta.txt", "alpha.txt", "beta.txt"]
            if results.get("_order") != expected_order:
                return make_test_result(
                    False, str(expected_order), str(results.get("_order")), None
                )

            if results.get("total") != [2, 5, 9]:
                return make_test_result(
                    False, "[2, 5, 9]", str(results.get("total")), None
                )

            return make_test_result(True, "sorted counts with total", stdout.strip(), None)
    except RuntimeError as e:
        return make_test_result(False, "compiled", str(e), None)


def test_missing_file_keeps_total(workspace):
    try:
        with CountTestContext(workspace) as ctx:
            present = ctx.create_file("one two\n", "present.txt")
            missing = workspace / "missing.txt"

            ret_code, stdout, stderr = ctx.run_count(
                [missing, present], ["-c", "-w", "-l"]
            )

            results = _parse_count_output(stdout)
            if ret_code == 0:
                return make_test_result(False, "nonzero exit", str(ret_code), None)

            if "cannot open file" not in stderr or "missing.txt" not in stderr:
                return make_test_result(
                    False, "missing-file error", stderr.strip(), None
                )

            if "missing.txt" in results:
                return make_test_result(
                    False, "no output for missing file", stdout.strip(), None
                )

            if results.get("present.txt") != [1, 2, 8]:
                return make_test_result(
                    False, "[1, 2, 8]", str(results.get("present.txt")), None
                )

            if results.get("total") != [1, 2, 8]:
                return make_test_result(
                    False, "[1, 2, 8]", str(results.get("total")), None
                )

            return make_test_result(True, "error handling with total", stdout.strip(), None)
    except RuntimeError as e:
        return make_test_result(False, "compiled", str(e), None)


def test_total_zero_for_unrequested_counts(workspace):
    try:
        with CountTestContext(workspace) as ctx:
            sample = ctx.create_file("a b\nc\n", "sample.txt")

            ret_code, stdout, stderr = ctx.run_count([sample], ["-l"])
            results = _parse_count_output(stdout)

            if ret_code != 0 or stderr.strip():
                return make_test_result(False, "successful run", stderr.strip(), None)

            if results.get("sample.txt") != [2]:
                return make_test_result(False, "[2]", str(results.get("sample.txt")), None)

            if results.get("total") != [2, 0, 0]:
                return make_test_result(
                    False, "[2, 0, 0]", str(results.get("total")), None
                )

            return make_test_result(True, "line-only output", stdout.strip(), None)
    except RuntimeError as e:
        return make_test_result(False, "compiled", str(e), None)

